$ErrorActionPreference='Continue'
$token=$env:GHL_PRIVATE_INTEGRATION_TOKEN
$base='https://services.leadconnectorhq.com'
$loc='TW8JsPW5NMnA3tfK2XLn'
$headers=@{ Authorization = "Bearer $token"; Version='2021-07-28'; Accept='application/json'; LocationId=$loc }
$urls=@(
"$base/opportunities",
"$base/opportunities/",
"$base/opportunities?locationId=$loc&limit=20",
"$base/opportunities/?limit=20",
"$base/opportunities/search?locationId=$loc&limit=20"
)
foreach($u in $urls){
  try { $r=Invoke-RestMethod -Method Get -Uri $u -Headers $headers; Write-Output "OK $u"; $r | ConvertTo-Json -Depth 4 | Select-Object -First 1 }
  catch { Write-Output "ERR $u :: $($_.Exception.Message)" }
}

