arguments.command:
$ErrorActionPreference='Stop'
$token=$env:GHL_PRIVATE_INTEGRATION_TOKEN
if(-not $token){'NO_TOKEN';exit 0}
$base='https://services.leadconnectorhq.com'
$loc='TW8JsPW5NMnA3tfK2XLn'
$headers=@{ Authorization = "Bearer $token"; Version='2021-07-28'; Accept='application/json'; 'Content-Type'='application/json' }
$opps=(Invoke-RestMethod -Method Post -Uri "$base/opportunities/search" -Headers $headers -Body (@{locationId=$loc;limit=100}|ConvertTo-Json)).opportunities
$targetStageByTag=@{
  'ebook-buyer'='f6101dbb-4a62-4d27-a93b-9cb05010abf9'
  'course-buyer'='6634a6bb-ed0f-429b-8266-260a8400b669'
  'lite-buyer'='32496284-c6d5-4e0d-85b9-708a5a60986b'
  'membership-active'='5572eab4-7f24-402c-bb95-69af32233438'
}
$changes=@()
foreach($o in $opps){
  $tags=@($o.contact.tags)
  foreach($t in $targetStageByTag.Keys){
    if($tags -contains $t){
      $stage=$targetStageByTag[$t]
      if($o.pipelineId -eq 'WwwiXO65toZOTQptzmWp' -and $o.pipelineStageId -ne $stage){
        $body=@{ pipelineId=$o.pipelineId; pipelineStageId=$stage; locationId=$loc; status=$o.status; name=$o.name; monetaryValue=$o.monetaryValue } | ConvertTo-Json
        Invoke-RestMethod -Method Put -Uri "$base/opportunities/$($o.id)" -Headers $headers -Body $body | Out-Null
        $changes += [pscustomobject]@{opportunityId=$o.id; contactId=$o.contactId; from=$o.pipelineStageId; to=$stage; reasonTag=$t}
      }
      break
    }
  }
}
if($changes.Count -eq 0){''} else {$changes | ConvertTo-Json -Depth 4}

